import { cacheTag } from 'next/cache';

const baseProducts = [
  { id: 1, name: 'Laptop', price: 999, inventory: 42, availability: 'In stock' },
  { id: 2, name: 'Phone', price: 699, inventory: 18, availability: 'In stock' },
  { id: 3, name: 'Tablet', price: 499, inventory: 9, availability: 'Low stock' },
  { id: 4, name: 'Headphones', price: 199, inventory: 61, availability: 'In stock' },
  { id: 5, name: 'Watch', price: 299, inventory: 27, availability: 'In stock' }
];

let catalog = baseProducts.map(product => ({ ...product }));
let catalogRevision = 1;
let lastSyncedAt = new Date();

const delay = ms => new Promise(resolve => setTimeout(resolve, ms));

export async function getCatalogSnapshot() {
  'use cache';
  cacheTag('products');

  await delay(80);

  return {
    revision: catalogRevision,
    lastSyncedAt: lastSyncedAt.toISOString(),
    products: catalog.map(product => ({ ...product }))
  };
}

export function syncCatalogSource() {
  catalogRevision += 1;
  lastSyncedAt = new Date();

  catalog = catalog.map((product, index) => {
    const priceStep = index % 2 === 0 ? 12 : 8;
    const inventoryStep = (catalogRevision + index) % 4;
    const inventory = Math.max(0, product.inventory - inventoryStep + 5);

    return {
      ...product,
      price: product.price + priceStep,
      inventory,
      availability: inventory > 12 ? 'In stock' : inventory > 0 ? 'Low stock' : 'Out of stock'
    };
  });
}


